 /// Returns the domain name for API compatibility.
 #[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
 pub unsafe extern "C" fn textdomain(domainname: *const c_char) -> *mut c_char {
+    let storage = text_domain_storage();
