-        DEFAULT_TEXT_DOMAIN.as_ptr() as *mut c_char
+        current.current
+    } else if unsafe { *domainname } == 0 {
+        current.current = DEFAULT_TEXT_DOMAIN.as_ptr() as *mut c_char;
+        current.current
